import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import { Card, CardContent, CardHeader, CardTitle } from './ui/card';
import { Button } from './ui/button';
import { Input } from './ui/input';
import { Home, Search, BookOpen, Calendar, Clock, User, Settings, ChevronRight, Edit } from 'lucide-react';

const TemplateBrowser = () => {
  const [templates, setTemplates] = useState([]);
  const [selectedTemplate, setSelectedTemplate] = useState(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [courseInfo, setCourseInfo] = useState({
    courseName: '',
    teacher: '',
    classroom: '',
    time: '',
    credits: ''
  });
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [images, setImages] = useState({});

  // 从后端获取模板数据
  useEffect(() => {
    const fetchTemplates = async () => {
      try {
        const response = await axios.get('/api/templates');
        const templatesData = response.data;

        // 加载所有模板图片并转换为Base64
        const imagePromises = templatesData.map(async (template) => {
          try {
            const imgResponse = await fetch(`http://localhost:3001${template.image}`);
            const blob = await imgResponse.blob();
            const reader = new FileReader();
            return new Promise((resolve) => {
              reader.onloadend = () => {
                resolve({ id: template.templateId, base64: reader.result });
              };
              reader.readAsDataURL(blob);
            });
          } catch (err) {
            console.error('加载图片失败:', err);
            return { id: template.templateId, base64: null };
          }
        });

        const imageResults = await Promise.all(imagePromises);
        const imagesMap = {};
        imageResults.forEach(result => {
          if (result.base64) {
            imagesMap[result.id] = result.base64;
          }
        });

        setImages(imagesMap);
        setTemplates(templatesData);
        setLoading(false);
      } catch (err) {
        setError('获取模板列表失败');
        setLoading(false);
      }
    };

    fetchTemplates();
  }, []);

  // 过滤模板
  const filteredTemplates = templates.filter(template =>
    (template.category || '').toLowerCase().includes(searchQuery.toLowerCase())
  );

  // 获取所有分类
  const categories = ['全部', ...new Set(templates.map(t => t.category || '默认'))];
  const [selectedCategory, setSelectedCategory] = useState('全部');

  // 根据分类过滤模板
  const categoryFilteredTemplates = selectedCategory === '全部' 
    ? filteredTemplates 
    : filteredTemplates.filter(t => (t.category || '默认') === selectedCategory);

  // 处理模板选择
  const handleSelectTemplate = (template) => {
    setSelectedTemplate(template);
    // 重置课程信息
    setCourseInfo({
      courseName: '',
      teacher: '',
      classroom: '',
      time: '',
      credits: ''
    });
  };

  // 处理课程信息变更
  const handleCourseInfoChange = (field, value) => {
    setCourseInfo(prev => ({
      ...prev,
      [field]: value
    }));
  };

  return (
    <div className="flex h-screen bg-gray-50">
      {/* 左侧边栏 */}
      <aside className="w-80 bg-white border-r border-gray-200 flex flex-col">
        {/* 侧边栏头部 */}
        <div className="p-6 border-b border-gray-200">
          <div className="flex items-center gap-2 mb-4">
            <BookOpen className="h-6 w-6 text-blue-600" />
            <h1 className="text-xl font-bold">课程模板</h1>
          </div>

          {/* 搜索框 */}
          <div className="relative">
            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-gray-400" />
            <Input
              type="text"
              placeholder="搜索模板..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="pl-10"
            />
          </div>
        </div>

        {/* 分类标签 */}
        <div className="px-6 py-3 border-b border-gray-200">
          <div className="flex gap-2 flex-wrap">
            {categories.map(category => (
              <Button
                key={category}
                variant={selectedCategory === category ? "default" : "outline"}
                size="sm"
                onClick={() => setSelectedCategory(category)}
                className="text-xs"
              >
                {category}
              </Button>
            ))}
          </div>
        </div>

        {/* 模板列表 */}
        <div className="flex-1 overflow-y-auto p-4">
          <div className="space-y-3">
            {categoryFilteredTemplates.map(template => (
              <Card
                key={template.templateId}
                className={`cursor-pointer transition-all hover:shadow-md ${
                  selectedTemplate?.templateId === template.templateId ? 'ring-2 ring-blue-500' : ''
                }`}
                onClick={() => handleSelectTemplate(template)}
              >
                <CardContent className="p-4">
                  <div className="flex gap-3">
                    <img
                      src={images[template.templateId] || `http://localhost:3001${template.image}`}
                      alt={`模板 ${template.templateId}`}
                      className="w-16 h-16 object-cover rounded"
                    />
                    <div className="flex-1 min-w-0">
                      <h3 className="font-semibold text-sm mb-1 truncate">
                        模板 #{template.templateId}
                      </h3>
                      <p className="text-xs text-gray-500 line-clamp-2">
                        {template.category || '默认分类'}
                      </p>
                      <div className="mt-2 flex items-center gap-1 text-xs text-blue-600">
                        <ChevronRight className="h-3 w-3" />
                        <span>点击查看详情</span>
                      </div>
                    </div>
                  </div>
                </CardContent>
              </Card>
            ))}
          </div>
        </div>

        {/* 侧边栏底部 */}
        <div className="p-4 border-t border-gray-200">
          <div className="flex gap-2">
            <Link to="/" className="flex-1">
              <Button variant="outline" className="w-full gap-2">
                <Home className="h-4 w-4" />
                返回首页
              </Button>
            </Link>
            <Button variant="outline" className="gap-2">
              <Settings className="h-4 w-4" />
              设置
            </Button>
          </div>
        </div>
      </aside>

      {/* 主内容区 */}
      <main className="flex-1 overflow-y-auto">
        {loading ? (
          <div className="h-full flex items-center justify-center">
            <div className="text-gray-600">加载中...</div>
          </div>
        ) : error ? (
          <div className="h-full flex items-center justify-center">
            <div className="text-red-600">{error}</div>
          </div>
        ) : !selectedTemplate ? (
          <div className="h-full flex items-center justify-center">
            <Card className="max-w-md">
              <CardHeader>
                <CardTitle className="text-center">欢迎使用课程模板系统</CardTitle>
              </CardHeader>
              <CardContent className="text-center text-gray-600">
                <p className="mb-4">请从左侧选择一个模板开始编辑课程信息</p>
                <div className="flex justify-center gap-4 text-sm">
                  <div className="flex items-center gap-2">
                    <BookOpen className="h-4 w-4" />
                    <span>浏览模板</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <Calendar className="h-4 w-4" />
                    <span>编辑课程</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <User className="h-4 w-4" />
                    <span>管理信息</span>
                  </div>
                </div>
              </CardContent>
            </Card>
          </div>
        ) : (
          <div className="p-8">
            <div className="max-w-4xl mx-auto">
              {/* 模板预览 */}
              <Card className="mb-6">
                <CardHeader>
                  <CardTitle className="flex items-center justify-between">
                    <div className="flex items-center gap-2">
                      <BookOpen className="h-5 w-5" />
                      模板 #{selectedTemplate.templateId}
                    </div>
                    <Link to={`/editor/${selectedTemplate.templateId}`}>
                      <Button className="gap-2">
                        <Edit className="h-4 w-4" />
                        编辑课表
                      </Button>
                    </Link>
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <img
                    src={images[selectedTemplate.templateId] || `http://localhost:3001${selectedTemplate.image}`}
                    alt={`模板 ${selectedTemplate.templateId}`}
                    className="w-full rounded-lg"
                  />
                  <p className="mt-4 text-gray-600">{selectedTemplate.category || '默认分类'}</p>
                </CardContent>
              </Card>


            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default TemplateBrowser;
